return ['x-generator'=>'GlotPress/4.0.1','translation-revision-date'=>'2022-01-26 08:06:37+0000','plural-forms'=>'nplurals=3; plural=(n == 1) ? 0 : ((n >= 2 && n <= 4) ? 1 : 2);','project-id-version'=>'Themes - Twenty Sixteen','language'=>'cs_CZ','messages'=>['Twenty Sixteen is a modernized take on an ever-popular WordPress layout — the horizontal masthead with an optional right sidebar that works perfectly for blogs and websites. It has custom color options with beautiful default color schemes, a harmonious fluid grid using a mobile-first approach, and impeccable polish in every detail. Twenty Sixteen will make your WordPress look beautiful everywhere.'=>'Twenty Sixteen je modernizovaná a populární šablona pro WordPress - horizontální záhlaví s možným pravým zarovnáním, které se hodí perfektně pro blogy a stránky. Můžete si nastavit vlastní barvy a vybrat nádherné schéma barev, harmonická responsivní mřížka využívající mobile-first přístup a vyladěnost do nejmenších detailů. Díky Twenty Sixteen bude vaše WordPressová stránka vypadat skvěle kdekoliv.','Twenty Sixteen'=>'Twenty Sixteen','Pre-Order Now'=>'Předobjednat nyní','My new book “Twenty Sixteen” is available for pre-order.'=>'Moje nová kniha „Twenty Sixteen“ je k dispozici k předobjednáni.','Call to Action'=>'Výzva k akci','— Takashi Irie'=>'— Takashi Irie','Twenty Sixteen will make your WordPress look beautiful everywhere.'=>'Díky Twenty Sixteen bude váš WordPress vypadat krásně všude.','Large Blockquote'=>'Velká bloková nabídka','The theme features a harmonious fluid grid using a mobile-first approach. The layout is a modern take on the horizontal masthead with an optional right sidebar.'=>'Šablona obsahuje harmonickou fluidní mřížku s využitím přístupu založeného na mobilních zařízeních. Uspořádání je moderním vzhledem vodorovné tiráži s volitelným pravým bočním panelem.','Twenty Sixteen will make your WordPress website look beautiful everywhere. Take advantage of its custom color options and beautiful default color schemes.'=>'Díky Twenty Sixteen bude váš web WordPress vypadat krásně všude. Využijte jeho vlastních barevných možností a krásných výchozích barevných schémat.','Big Title with Two Columns Text'=>'Velký titul se dvěma sloupci textu','Twenty Sixteen will make your WordPress website look beautiful everywhere. Take advantage of custom color options, beautiful default color schemes, a harmonious fluid grid using a mobile-first approach, and impeccable polish in every detail.'=>'Díky Twenty Sixteen bude váš web WordPress vypadat krásně všude. Využijte možnosti vlastních barev, krásná výchozí barevná schémata, harmonickou mřížku s využitím přístupu založeného na mobilních zařízeních a dokonalý lesk v každém detailu.','Twenty Sixteen is a modern take on the horizontal masthead with an optional right sidebar. It works perfectly for WordPress websites and blogs.'=>'Twenty Sixteen je moderní pohled na vodorovnou tiráž s volitelným pravým bočním panelem. Funguje perfektně pro weby a blogy WordPress.','Large heading with short description'=>'Velký nadpis s krátkým popisem','Bright Red'=>'Jasně červená','Dark Red'=>'Tmavě červená','Medium Brown'=>'Sytě hnědá','Dark Brown'=>'Tmavě hnědá','Light Blue'=>'Světle modrá','Bright Blue'=>'Jasná modrá','Blue Gray'=>'Šedomodrá','White'=>'Bílá','Light Gray'=>'Světle šedá','Medium Gray'=>'Středně šedá','Dark Gray'=>'Tmavě šedá','Continue reading<span class="screen-reader-text"> "%s"</span>'=>'Pokračovat ve čtení<span class="screen-reader-text"> "%s"</span>','Edit<span class="screen-reader-text"> "%s"</span>'=>'Upravit<span class="screen-reader-text"> "%s"</span>','Red'=>'Červený','comments titleOne thought on &ldquo;%s&rdquo;'=>'Jeden komentář u &ldquo;%s&rdquo;','submit buttonSearch'=>'Hledání','placeholderSearch &hellip;'=>'Hledat &hellip;','labelSearch for:'=>'Hledat:','Footer Social Links Menu'=>'Menu sociálních odkazů v patičce','Footer Primary Menu'=>'Hlavní menu patičky','Add widgets here to appear in your sidebar.'=>'R